SELECT 
FROM points p
WHERE p.id = #{id}

SELECT 
FROM points p
WHERE p.user_id = #{userId}
ORDER BY p.create_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*)
FROM points
WHERE user_id = #{userId}

SELECT , u.username FROM points p LEFT JOIN user u ON p.user_id = u.id
AND u.username LIKE CONCAT('%', #{username}, '%')
ORDER BY p.create_time DESC LIMIT #{offset}, #{limit}

SELECT 
FROM points p
WHERE p.user_id = #{userId}
  AND p.type = #{type}
ORDER BY p.create_time DESC
